import type { ViewUpdate } from '@codemirror/view';
import type { MutableRefObject } from 'react';

import type { FilterFieldSuggestionsContext } from '../suggestions/suggestions-extension.js';
import { getStatementStatus } from '../utils/get-statement-status.js';
import { getStatementCursorAtPosition } from '../utils/tree-navigation.js';

export function handleEditMode(
  update: ViewUpdate,
  suggestionsContext: MutableRefObject<
    FilterFieldSuggestionsContext | undefined
  >,
) {
  if (!update.focusChanged) {
    return;
  }

  const { view, state } = update;
  const cursorPos = state.selection.main.anchor;
  const statementStatus = getStatementStatus(
    getStatementCursorAtPosition(cursorPos, state),
  );
  const currentStatement = suggestionsContext.current?.currentStatement;

  const isAtEnd = cursorPos === state.doc.length;
  // The current value doesn't have a trailing space already.
  const hasTrailingSpace = state.sliceDoc(state.doc.length - 1) === ' ';
  // Should not add a space after a group bracket.
  const hasTrailingBracket =
    state.sliceDoc(state.doc.length - 1) === ')' &&
    currentStatement?.comparisonOperator?.type !== 'InclusionOperator';
  const isStatementComplete = statementStatus === 'complete';

  const shouldEnterEditMode =
    // Focus is moved to the filter field.
    view.hasFocus &&
    !hasTrailingSpace &&
    !hasTrailingBracket &&
    isStatementComplete &&
    isAtEnd;

  if (!shouldEnterEditMode) {
    return;
  }

  const transaction = {
    changes: {
      from: state.doc.length,
      to: state.doc.length,
      insert: ' ',
    },
    selection: { anchor: state.doc.length + 1 },
  };
  view.dispatch(transaction);
}
